    level: "intermediate",
    q: "Viết hook useLocalStorage trong React?",
    a: "`function useLocalStorage(key, initial) { const [value, setValue] = useState(() => { try { const item = localStorage.getItem(key); return item ? JSON.parse(item) : initial; } catch { return initial; } }); useEffect(() => { localStorage.setItem(key, JSON.stringify(value)); }, [key, value]); return [value, setValue]; }` Test khả năng viết custom hooks.",
    q_en: "Write a useLocalStorage hook in React.",
    a_en: "`function useLocalStorage(key, initial) { const [value, setValue] = useState(() => { try { const item = localStorage.getItem(key); return item ? JSON.parse(item) : initial; } catch { return initial; } }); useEffect(() => { localStorage.setItem(key, JSON.stringify(value)); }, [key, value]); return [value, setValue]; }` Tests the ability to write custom hooks with side effects.",
